-- Verify paradas 714 and 715 now have flowcat 046 and localizacion AVE. SAN JORGE
SELECT cobertizo_id, localizacion, flow_cat, orientacion FROM paradas 
WHERE cobertizo_id IN ('714', '715') 
ORDER BY cobertizo_id, orientacion;

-- Confirm flowcat 093 is now empty
SELECT COUNT(*) as remaining_093 FROM paradas WHERE flow_cat = '093';

-- Confirm flowcat 046 now has the paradas
SELECT cobertizo_id, localizacion, flow_cat FROM paradas WHERE flow_cat = '046' ORDER BY cobertizo_id;

